async function main() {
  // Get vendedor IDs
  const vendedores = await p.vendedor.findMany({ where: { ativo: true }, select: { id: true, nomeExibicao: true } });
  console.log('Vendedores:', vendedores.map(v => `${v.nomeExibicao} (id=${v.id})`).join(', '));

  const lucasId = vendedores.find(v => v.nomeExibicao === 'Lucas')?.id;
  const gabrielId = vendedores.find(v => v.nomeExibicao === 'Gabriel')?.id;

  if (!lucasId) { console.error('Lucas nao encontrado!'); return; }
  if (!gabrielId) { console.error('Gabriel nao encontrado!'); return; }

  console.log(`Lucas: vendedorId=${lucasId}, Gabriel: vendedorId=${gabrielId}`);
  console.log(`Total leads para importar: ${LEADS.length}`);

  let importados = 0;
  let erros = 0;
  let duplicatas = 0;

  for (let i = 0; i < LEADS.length; i++) {
    const l = LEADS[i];
    try {
      // Check duplicate by phone
      const existe = await p.lead.findFirst({ where: { telefone: l.telefone } });
      if (existe) { duplicatas++; continue; }

      const vendedorId = l.closer === 'gabriel' ? gabrielId : lucasId;
      const pontuacao = l.canal === 'bio' ? 60 : 35;
      const classe = pontuacao >= 75 ? 'A' : pontuacao >= 45 ? 'B' : 'C';

      await p.lead.create({
        data: {
          nome: l.nome,
          telefone: l.telefone,
          canal: l.canal,
          pontuacao,
          classe,
          etapaFunil: l.etapaFunil,
          status: l.status,
          vendedorId,
          vendaRealizada: l.vendaRealizada || false,
          valorVenda: l.valorVenda || null,
          formularioTitulo: 'Importado da planilha',
          dataPreenchimento: l.dataInicio ? new Date(l.dataInicio) : new Date(),
          dataAtribuicao: new Date(),
          dadosRespondi: { statusOriginal: l.statusOriginal, importadoDe: 'planilha' },
        },
      });

      importados++;
      if (importados % 100 === 0) console.log(`  ... ${importados} importados`);
    } catch (err) {
      erros++;
      if (erros <= 5) console.error(`Erro lead ${l.nome}: ${err.message}`);
    }
  }

  // Update leads_ativos count
  const lucasLeads = await p.lead.count({ where: { vendedorId: lucasId, status: { notIn: ['convertido', 'perdido'] } } });
  const gabrielLeads = await p.lead.count({ where: { vendedorId: gabrielId, status: { notIn: ['convertido', 'perdido'] } } });

  await p.vendedor.update({ where: { id: lucasId }, data: { leadsAtivos: lucasLeads } });
  await p.vendedor.update({ where: { id: gabrielId }, data: { leadsAtivos: gabrielLeads } });

  console.log('\n========== RESULTADO ==========');
  console.log(`Importados: ${importados}`);
  console.log(`Duplicatas (ja existiam): ${duplicatas}`);
  console.log(`Erros: ${erros}`);
  console.log(`Lucas leads ativos: ${lucasLeads}`);
  console.log(`Gabriel leads ativos: ${gabrielLeads}`);
}

main().catch(e => console.error(e)).finally(() => p.$disconnect());
